+    #[test]
+    fn assignment_strategy_debug_clone_copy_eq() {
+        let s = AssignmentStrategy::Striped;
+        let dbg = format!("{s:?}");
+        assert!(dbg.contains("Striped"), "{dbg}");
+        let copied = s;
+        let cloned = s.clone();
